<?php
namespace App\Domain\Combat;use App\Domain\Combat\Data\CombatAction;use App\Domain\Combat\Data\CombatCommand;use App\Domain\Combat\Data\CombatParticipantState;use App\Domain\Combat\Data\CombatState;use App\Domain\Combat\Data\CombatStepResult;use App\Domain\Random\RandomNumberGenerator;use InvalidArgumentException;
final class CombatActionResolver {private $rng;private $turnOrder;public function __construct(RandomNumberGenerator $rng,CombatTurnOrder $turnOrder){$this->rng=$rng;$this->turnOrder=$turnOrder;}public function resolve(CombatState $state,CombatCommand $command):CombatStepResult{if($state->status()!==CombatStateStatus::IN_PROGRESS||$command->actionType()!==CombatActionType::BASIC_ATTACK)throw new InvalidArgumentException('Invalid combat action.');$actor=$state->participant($command->actorIdentifier());$target=$state->participant($command->targetIdentifier());if(!$actor||!$target||!$actor->alive()||!$target->alive()||$actor->identifier()===$target->identifier()||$actor->sideIdentifier()===$target->sideIdentifier()||$actor->identifier()!==$state->nextActorIdentifier())throw new InvalidArgumentException('Invalid actor or target.');$a=$actor->stats();$d=$target->stats();$chance=max(5,min(95,75+$a->accuracyRate()-$d->evasionRate()));$roll=$this->rng->randomInt(1,10000);$hit=$roll<=(int)round($chance*100);$cc=max(0,min(100,$a->criticalChance()));$cr=null;$critical=false;$damage=0;if($hit){$cr=$this->rng->randomInt(1,10000);$critical=$cr<=(int)round($cc*100);$damage=max(1,(int)round($a->attack()*(1-$d->damageReductionRate()/100)*($critical?$a->criticalDamageMultiplier():1)));}$after=max(0,$target->currentHealth()-$damage);$updated=new CombatParticipantState($d,$after,$target->sideIdentifier(),$target->position());$participants=array_map(function($p)use($updated){return$p->identifier()===$updated->identifier()?$updated:$p;},$state->participants());$action=new CombatAction($state->roundNumber(),$actor->identifier(),$target->identifier(),round($chance,2),$roll/100,$hit,round($cc,2),$cr===null?null:$cr/100,$critical,$damage,$target->currentHealth(),$after);$players=$this->living($participants,CombatSide::PLAYERS);$enemies=$this->living($participants,CombatSide::ENEMIES);if(!$players||!$enemies){$status=!$players&&!$enemies?CombatResultStatus::DRAW:(!$enemies?CombatResultStatus::CHARACTER_VICTORY:CombatResultStatus::MONSTER_VICTORY);$next=new CombatState($participants,$state->roundNumber(),[],0,$status);return new CombatStepResult($state,$command,$action,$next);}$order=$state->actionOrder();$index=$state->currentActionIndex()+1;while(isset($order[$index])&&!$this->alive($participants,$order[$index]))$index++;$round=$state->roundNumber();if(!isset($order[$index])){$round++;$order=$this->turnOrder->build($participants);$index=0;}$next=new CombatState($participants,$round,$order,$index,CombatStateStatus::IN_PROGRESS);return new CombatStepResult($state,$command,$action,$next);}private function living($participants,$side){return array_values(array_filter($participants,function($p)use($side){return$p->sideIdentifier()===$side&&$p->alive();}));}private function alive($participants,$id){foreach($participants as $p)if($p->identifier()===$id)return$p->alive();return false;}}
